# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request
from collections import Counter
from PIL import Image

app = Flask(__name__)

# Memory storage for simplicity
IMAGES = {}
LABELS = {}

@app.route('/images/upload', methods=['POST'])
def upload_image():
    file = Image.open(request.files['file'])
    image_id = str(len(IMAGES) + 1)
    IMAGES[image_id] = file
    LABELS[image_id] = []
    return {'id': image_id}

@app.route('/images/annotate/<image_id>', methods=['POST'])
def annotate_image(image_id):
    if image_id not in IMAGES:
        return {'error': 'No such image'}, 400
  
    data = request.json
    annotator = data['annotator']
    label = data['label']
    LABELS[image_id].append((annotator, label))
  
    return {'status': 'success'}